const user = { name: "Nami" };
const items = [{ id: 1, name: "蘋果" }, { id: 2, name: "香蕉" }];

// @if (user) { 哈囉 {{user.name}} }
console.log(user ? "哈囉 " + user.name : "請先登入");

// @for (item of items; track item.id) { <li>{{item.name}}</li> }
