// 模擬 Angular Signal
function signal(initial) {
  let value = initial;
  const s = () => value;            // 讀：加 ()
  s.set = (v) => { value = v; };
  s.update = (fn) => { value = fn(value); };
  return s;
}

const count = signal(0);
console.log("初值:", count());   // 0
count.set(5);
console.log("set 後:", count()); // 5
count.update(n => n + 1);
console.log("update 後:", count()); // 6

// 模擬 [(ngModel)] 雙向綁定
